        {cols.map((col, i) => (<div key={i}><div style={{ fontFamily: "'Libre Franklin', sans-serif", fontSize: 10, letterSpacing: 3, color: C.red, textTransform: "uppercase", marginBottom: 12, fontWeight: 500 }}>{col.title}</div>{col.links.map((l, j) => (<a key={j} href={l.u} style={{ display: "block", fontFamily: "'Libre Franklin', sans-serif", fontSize: 14, color: "rgba(255,255,255,0.4)", textDecoration: "none", padding: "3px 0" }}>{l.t}</a>))}</div>))}
